def encode(message):
    vowels = 'aeiou'
    result = []
    for char in message:
        if char.isalpha():
            if char.lower() in vowels:
                new_char = chr(((ord(char.lower()) - ord('a') + 2) % 26) + ord('a'))
                if char.isupper():
                    new_char = new_char.upper()
                result.append(new_char)
            else:
                result.append(char.swapcase())
        else:
            result.append(char)
    return ''.join(result)
